svg.script:
//
(function() {
  var svg  = document.getElementById('root');
  var pie  = document.getElementById('pie');
  var ns   = 'http://www.w3.org/2000/svg';
  var R    = 210, PUSH = 14;

  function easeOutCubic(t) { return 1 - Math.pow(1-t, 3); }
  function easeOutBack(t)  { var c1=1.70158,c3=c1+1; return 1+c3*Math.pow(t-1,3)+c1*Math.pow(t-1,2); }

  var sliceEls  = Array.prototype.slice.call(svg.querySelectorAll('.slice-g'));
  var SPIN_DUR  = 550, STAGGER = 225, FADE_DUR = 800;
  var startTime = null;

  sliceEls.forEach(function(g){ g.style.opacity = '0'; });
  var holeEl = document.getElementById('hole-group');
  holeEl.style.opacity = '0';

  function animateSlices(ts) {
    if (!startTime) startTime = ts;
    var elapsed = ts - startTime;

    sliceEls.forEach(function(g, i) {
      var t     = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / SPIN_DUR));
      var tFade = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / FADE_DUR));
      var span  = parseFloat(g.getAttribute('data-span'));
      g.setAttribute('transform', 'rotate('+(easeOutBack(t)*span-span).toFixed(3)+')');
      g.style.opacity = easeOutCubic(tFade).toFixed(3);
    });

    var holeStart = (sliceEls.length-1)*STAGGER + SPIN_DUR*0.7;
    holeEl.style.opacity =
      easeOutCubic(Math.max(0, Math.min(1, (elapsed-holeStart)/300))).toFixed(3);

    var totalDur = (sliceEls.length-1)*STAGGER + SPIN_DUR + 300;
    if (elapsed < totalDur) {
      requestAnimationFrame(animateSlices);
    } else {
      sliceEls.forEach(function(g) {
        g.removeAttribute('transform');
        g.style.opacity = '';
      });
      holeEl.style.opacity = '1';
      pie.classList.add('ready');
    }
  }

  requestAnimationFrame(animateSlices);

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  var tipLayer = document.getElementById('tip-layer');
  var tipMap   = {};

  sliceEls.forEach(function(g) {
    var sliceId = g.id;
    var midDeg  = parseFloat(g.getAttribute('data-mid'));
    var label   = g.getAttribute('data-label');
    var val     = g.getAttribute('data-val');
    var pct     = g.getAttribute('data-pct');
    var midRad  = midDeg * Math.PI / 180;
    var dx = Math.cos(midRad), dy = Math.sin(midRad);
    var cx = 310, cy = 330;
    var bw = Math.max(90, label.length*7+30);
    var bh = 56, hw = bw/2, hh = bh/2, TAIL = 14;
    var tipX = cx+dx*R, tipY = cy+dy*R;
    var bCx = tipX, bCy = tipY-hh-TAIL;
    if (bCx-hw < 8)    bCx = 8+hw;
    if (bCx+hw > 1092) bCx = 1092-hw;
    if (bCy-hh < 8)    bCy = 8+hh;
    var baseY = bCy+hh;
    var pushTx = 'translate('+(dx*PUSH).toFixed(1)+','+(dy*PUSH).toFixed(1)+')';
    var pushX  = dx*PUSH, pushY = dy*PUSH;

    var tipG = el('g', {'class':'tip','data-for':sliceId});
    tipLayer.appendChild(tipG);
    tipMap[sliceId] = tipG;

    tipG.appendChild(el('rect',{x:(bCx-hw).toFixed(1),y:(bCy-hh).toFixed(1),width:bw,height:bh,rx:9,'class':'bub-bg'}));
    tipG.appendChild(el('rect',{x:(bCx-hw).toFixed(1),y:(bCy-hh).toFixed(1),width:bw,height:bh,rx:9,'class':'bub-bdr'}));
    tipG.appendChild(el('polygon',{points:(bCx-10)+','+(baseY-1)+' '+(bCx+10)+','+(baseY-1)+' '+bCx+','+tipY,'class':'bub-tip'}));
    tipG.appendChild(el('path',{d:'M'+(bCx-10)+','+(baseY-1)+' '+bCx+','+tipY+' '+(bCx+10)+','+(baseY-1),'class':'bub-bdr',fill:'none','stroke-width':'1'}));
    var tv=el('text',{x:bCx.toFixed(1),y:(bCy-10).toFixed(1),'text-anchor':'middle','dominant-baseline':'central','class':'bub-val'}); tv.textContent=val; tipG.appendChild(tv);
    var tl=el('text',{x:bCx.toFixed(1),y:(bCy+5).toFixed(1), 'text-anchor':'middle','dominant-baseline':'central','class':'bub-lbl'}); tl.textContent=label; tipG.appendChild(tl);
    var tp=el('text',{x:bCx.toFixed(1),y:(bCy+18).toFixed(1),'text-anchor':'middle','dominant-baseline':'central','class':'bub-pct'}); tp.textContent=pct; tipG.appendChild(tp);

    var pathEl = document.getElementById('sp'+sliceId.replace('sl',''));

    g.addEventListener('mouseenter', function() {
      pie.classList.add('hovering');
      sliceEls.forEach(function(s){ s.classList.remove('active'); });
      g.classList.add('active');
      if (pathEl) pathEl.setAttribute('transform', pushTx);
      tipMap[sliceId].style.opacity = '1';
      tipMap[sliceId].setAttribute('transform','translate('+pushX.toFixed(1)+','+pushY.toFixed(1)+')');
    });
    g.addEventListener('mouseleave', function() {
      pie.classList.remove('hovering');
      g.classList.remove('active');
      if (pathEl) pathEl.removeAttribute('transform');
      tipMap[sliceId].style.opacity = '';
      tipMap[sliceId].removeAttribute('transform');
    });
  });

  var isDark = false;
  function setMode(wantDark) {
    if (wantDark===isDark) return;
    isDark = wantDark;
    var thumb=document.getElementById('tthumb'), lbl=document.getElementById('tlabel');
    if (wantDark) { svg.classList.add('dark');   thumb.setAttribute('cx','52'); lbl.textContent='Light'; }
    else          { svg.classList.remove('dark'); thumb.setAttribute('cx','16'); lbl.textContent='Dark';  }
  }
  document.getElementById('dark-toggle').addEventListener('click', function(){ setMode(!isDark); });
  document.getElementById('print-toggle').addEventListener('click', function(){
    var thumb=document.getElementById('pthumb'),lbl=document.getElementById('plabel');
    if (svg.classList.toggle('print')){ thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                              { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });
  window.setMode = setMode;
  window.addEventListener('message', function(e){ if(e.data&&e.data.type==='setMode') setMode(e.data.dark); });
  setMode(window.location.href.indexOf('theme=dark')!==-1);
})();
//
